-- OpenResty Lua script to handle user permissions and authentication tokens
local jwt = require 'resty.jwt' -- JWT library
local ngx_md5 = require "ngx.md5"  -- MD5 library for generating hash of token

-- Function to validate the JWT token
function validate_token(req)
    local auth_header = req:get_headers()["authorization"]
    if not auth_header then
        return false, "Missing Authorization Header"
    end

    -- Extract Bearer Token from header
    local _, token = string.gsub(auth_header, '^Bearer %s+', '')
    
    -- Decode JWT token
    local decoded_token, err = jwt:decode(token)
    if not decoded_token then
        return false, "Invalid Token"
    end
  
    -- Check user role and skip permission checks for certain endpoints
    if ngx.var.uri ~= "/admin" or ngx.var.uri ~= "/api" then
      if not decoded_token["role"] then
          return false, "Invalid Token: Missing Role Claim"
      elseif decoded_token["role"] == "admin" then
          -- Grant admin access
          ngx.ctx.user = { role='admin', userid=decoded_token['sub'] }
          return true, "Admin Access Granted"
      elseif decoded_token["role"] == "user" then
          -- Grant user access
          ngx.ctx.user = { role='user', userid=decoded_token['sub'] }
          return true, "User Access Granted"
      else
          return false, "Invalid Token: Invalid Role Claim"
      end
    end
  
    -- Grant access for other endpoints
    ngx.ctx.user = { role='guest', userid=decoded_token['sub'] }
    return true, "Guest Access Granted"
end